INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "", "omp_talk_joy2", "", 112411, 3, 0, 1030036, "", 3, 1);
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "", "vo_omp_7003_006", "", "vo_omp_7003", 21, "", 1030037, 0, 3, 0);
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES (1, "", "あっ、たしかにそうですね！\nまずは目の前のぴにゃこら太さんに\n認めてもらわなきゃですし♪", "", 112411, 11, "", 1030038, 1, 3, 10);
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "", "", "", 0, 91, "", 1030039, "", 3, "");
