INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES (1, "", "そういうことじゃないんだけど…\n集めるのあきらめてくれたなら\nまぁ、いっか！\nその調子で頑張ってこう、しまむー！", "", 112611, 11, "", 1030043, 1, 3, 10);
