INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES (1, "", "今思うと…最初のゲリラLIVEは\nほんとうにいっぱいいっぱいでしたね", "", 112411, 11, "", 1070016, 1, 7, 10);
