INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "", "vo_omp_7007_002", "", "vo_omp_7007", 21, "", 1070025, 0, 7, 0);
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES (1, "", "ペコリーヌさまの場合は、\n空腹で締め付けられていた\n可能性もありますが…", "", 105931, 11, "", 1070026, 1, 7, 10);
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "", "", "", 0, 91, "", 1070027, "", 7, "");
