INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "", "omp_talk_worry", "", 112611, 3, 0, 1070034, "", 7, 1);
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "", "vo_omp_7007_004", "", "vo_omp_7007", 21, "", 1070035, 0, 7, 0);
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES (1, "", "もうっ、キャルキャル～\nあんま言わないでよ～！\n私たちだってわかってるんだからさ～", "", 112611, 11, "", 1070036, 1, 7, 10);
